  <div class="task-list-page">
    <div class="page-header">
      <h2>我的任务列表</h2>
      <p>管理您的日常任务，提高工作效率</p>
    </div>

    <div class="task-manager">
      <div class="add-task-section">
        <input
          v-model="newTask"
          type="text"
          placeholder="输入新任务..."
          @keyup.enter="addTask"
          class="task-input"
        />
        <button @click="addTask" class="add-btn">添加任务</button>
      </div>

      <div class="stats">
        <div class="stat-item">
          <span class="stat-number">{{ totalTasks }}</span>
          <span class="stat-label">总任务数</span>
        </div>
        <div class="stat-item">
          <span class="stat-number">{{ pendingTasks }}</span>
          <span class="stat-label">待完成</span>
        </div>
        <div class="stat-item">
          <span class="stat-number">{{ completedTasks }}</span>
          <span class="stat-label">已完成</span>
        </div>
      </div>

      <div class="task-filters">
        <button 
          @click="filter = 'all'" 
          :class="{ active: filter === 'all' }"
          class="filter-btn"
        >
          全部
        </button>
        <button 
          @click="filter = 'pending'" 
          :class="{ active: filter === 'pending' }"
          class="filter-btn"
        >
          待完成
        </button>
        <button 
          @click="filter = 'completed'" 
          :class="{ active: filter === 'completed' }"
          class="filter-btn"
        >
          已完成
        </button>
      </div>

      <div class="tasks-container">
        <div v-if="filteredTasks.length === 0" class="empty-state">
          <p>暂无任务，开始添加您的第一个任务吧！</p>
        </div>

        <div v-else class="tasks-list">
          <div 
            v-for="task in filteredTasks" 
            :key="task.id"
            :class="['task-item', { completed: task.completed }]"
          >
            <div class="task-content">
              <input 
                type="checkbox" 
                v-model="task.completed"
                class="task-checkbox"
              />
              <span class="task-text">{{ task.text }}</span>
            </div>
            <button 
              @click="removeTask(task.id)"
              class="delete-btn"
            >
              删除
            </button>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script setup>
import { ref, computed } from 'vue'

const newTask = ref('')
const filter = ref('all')

// 初始示例任务
const tasks = ref([
  { id: 1, text: '完成项目需求文档', completed: false },
  { id: 2, text: '准备团队会议材料', completed: true },
  { id: 3, text: '学习Vue3新特性', completed: false },
  { id: 4, text: '代码审查', completed: false },
  { id: 5, text: '更新项目依赖', completed: true }
])

const addTask = () => {
  if (newTask.value.trim()) {
    tasks.value.push({
      id: Date.now(),
      text: newTask.value.trim(),
      completed: false
    })
    newTask.value = ''
  }
}

const removeTask = (id) => {
  tasks.value = tasks.value.filter(task => task.id !== id)
}

const totalTasks = computed(() => tasks.value.length)
const pendingTasks = computed(() => tasks.value.filter(t => !t.completed).length)
const completedTasks = computed(() => tasks.value.filter(t => t.completed).length)

const filteredTasks = computed(() => {
  switch (filter.value) {
    case 'pending':
      return tasks.value.filter(t => !t.completed)
    case 'completed':
      return tasks.value.filter(t => t.completed)
    default:
      return tasks.value
  }
})
</script>

